"use client";

import { useState, useEffect, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  Heart,
  Loader2,
  ArrowLeft,
  Calendar,
  Clock,
  User,
  Building2,
  Video,
  FileText,
  CreditCard,
  CheckCircle2,
} from "lucide-react";

interface Hospital {
  id: string;
  name: string;
  city: string;
}

interface Doctor {
  id: string;
  name: string;
  specialization: string;
  consultationFee: number;
}

interface Slot {
  id: string;
  date: string;
  startTime: string;
  endTime: string;
}

function NewAppointmentForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { user, isLoading: authLoading } = useAuth();

  const initialHospital = searchParams.get("hospital") || "";
  const initialDoctor = searchParams.get("doctor") || "";

  // Data states
  const [hospitals, setHospitals] = useState<Hospital[]>([]);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [slots, setSlots] = useState<Slot[]>([]);

  // Selection states
  const [selectedHospital, setSelectedHospital] = useState(initialHospital);
  const [selectedDoctor, setSelectedDoctor] = useState(initialDoctor);
  const [selectedSlot, setSelectedSlot] = useState("");
  const [appointmentType, setAppointmentType] = useState<"IN_PERSON" | "VIDEO_CALL">("IN_PERSON");
  const [reason, setReason] = useState("");

  // Loading states
  const [loadingHospitals, setLoadingHospitals] = useState(false);
  const [loadingDoctors, setLoadingDoctors] = useState(false);
  const [loadingSlots, setLoadingSlots] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);

  // Fetch Hospitals
  useEffect(() => {
    async function loadHospitals() {
      try {
        setLoadingHospitals(true);
        const res = await fetch("/api/hospitals");
        const data = await res.json();
        if (data.success) {
          setHospitals(data.data);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingHospitals(false);
      }
    }
    loadHospitals();
  }, []);

  // Fetch Doctors when Hospital changes
  useEffect(() => {
    if (!selectedHospital) {
      setDoctors([]);
      setSelectedDoctor("");
      return;
    }

    async function loadDoctors() {
      try {
        setLoadingDoctors(true);
        const res = await fetch(`/api/hospitals/${selectedHospital}`);
        const data = await res.json();
        if (data.success) {
          setDoctors(data.data.doctors || []);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingDoctors(false);
      }
    }
    loadDoctors();
  }, [selectedHospital]);

  // Fetch Slots when Doctor changes
  useEffect(() => {
    if (!selectedDoctor) {
      setSlots([]);
      setSelectedSlot("");
      return;
    }

    async function loadSlots() {
      try {
        setLoadingSlots(true);
        const res = await fetch(`/api/slots?doctorId=${selectedDoctor}`);
        const data = await res.json();
        if (data.success) {
          setSlots(data.data.slots || []);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSlots(false);
      }
    }
    loadSlots();
  }, [selectedDoctor]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) {
      setError("Please select an appointment time slot.");
      return;
    }

    setSaving(true);
    setError("");

    try {
      const res = await fetch("/api/appointments", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          hospitalId: selectedHospital,
          doctorId: selectedDoctor,
          slotId: selectedSlot,
          type: appointmentType,
          reason,
        }),
      });

      const data = await res.json();
      if (data.success) {
        setSuccess(true);
        setTimeout(() => {
          router.push("/dashboard");
        }, 2000);
      } else {
        setError(data.error || "Failed to book appointment. Please try again.");
      }
    } catch (err) {
      setError("Connection failure. Please try again.");
    } finally {
      setSaving(false);
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <Loader2 className="w-8 h-8 text-primary-600 animate-spin" />
      </div>
    );
  }

  if (success) {
    return (
      <div className="min-h-screen bg-surface-secondary flex items-center justify-center p-4">
        <div className="bg-white border border-border rounded-3xl p-8 max-w-md w-full text-center shadow-xl space-y-4 animate-scale-in">
          <div className="w-16 h-16 bg-emerald-50 rounded-full flex items-center justify-center mx-auto text-emerald-600">
            <CheckCircle2 className="w-10 h-10" />
          </div>
          <h2 className="text-xl font-bold text-text-primary">Appointment Booked!</h2>
          <p className="text-sm text-text-secondary">
            Your appointment has been successfully requested. Redirecting you back to your dashboard...
          </p>
        </div>
      </div>
    );
  }

  const selectedDoctorObj = doctors.find((d) => d.id === selectedDoctor);

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.back()}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Schedule Consultation</span>
          </div>
          <div className="w-8 h-8 bg-primary-100 rounded-lg flex items-center justify-center">
            <Heart className="w-4.5 h-4.5 text-primary-600" />
          </div>
        </div>
      </header>

      {/* Form Container */}
      <main className="max-w-3xl mx-auto px-4 py-8">
        <div className="bg-white border border-border rounded-3xl overflow-hidden shadow-xs">
          <div className="p-6 border-b border-border bg-surface-secondary/20">
            <h1 className="text-xl font-extrabold text-text-primary">Book Consultation Session</h1>
            <p className="text-xs text-text-secondary mt-1">
              Select department specialist, time slot, and setup online/offline consulting parameters.
            </p>
          </div>

          <form onSubmit={handleSubmit} className="p-6 space-y-6">
            {error && (
              <div className="p-4 bg-red-50 border border-red-200 text-red-700 text-sm font-semibold rounded-xl">
                {error}
              </div>
            )}

            {/* Step 1: Hospital Selector */}
            <div className="space-y-2">
              <label className="text-xs font-bold text-text-primary uppercase tracking-wider flex items-center gap-1.5">
                <Building2 className="w-4 h-4 text-text-muted" /> Select Healthcare Facility
              </label>
              {loadingHospitals ? (
                <div className="h-10 border border-border rounded-xl flex items-center px-3 bg-surface-secondary text-xs text-text-muted gap-2">
                  <Loader2 className="w-4 h-4 animate-spin text-primary-600" /> Loading facilities...
                </div>
              ) : (
                <select
                  required
                  value={selectedHospital}
                  onChange={(e) => setSelectedHospital(e.target.value)}
                  className="w-full text-sm border border-border rounded-xl px-3.5 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                >
                  <option value="">Choose Hospital...</option>
                  {hospitals.map((h) => (
                    <option key={h.id} value={h.id}>
                      {h.name} — {h.city}
                    </option>
                  ))}
                </select>
              )}
            </div>

            {/* Step 2: Doctor Selector */}
            {selectedHospital && (
              <div className="space-y-2 animate-slide-up">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider flex items-center gap-1.5">
                  <User className="w-4 h-4 text-text-muted" /> Select Specialist / Department
                </label>
                {loadingDoctors ? (
                  <div className="h-10 border border-border rounded-xl flex items-center px-3 bg-surface-secondary text-xs text-text-muted gap-2">
                    <Loader2 className="w-4 h-4 animate-spin text-primary-600" /> Loading roster...
                  </div>
                ) : doctors.length === 0 ? (
                  <div className="p-3 bg-amber-50 border border-amber-200 text-amber-800 text-xs rounded-xl font-medium">
                    No active doctors onboarded for this hospital yet.
                  </div>
                ) : (
                  <select
                    required
                    value={selectedDoctor}
                    onChange={(e) => setSelectedDoctor(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  >
                    <option value="">Choose Doctor...</option>
                    {doctors.map((d) => (
                      <option key={d.id} value={d.id}>
                        {d.name} ({d.specialization}) — Fee: ₹{d.consultationFee}
                      </option>
                    ))}
                  </select>
                )}
              </div>
            )}

            {/* Step 3: Slots Selector */}
            {selectedDoctor && (
              <div className="space-y-3 animate-slide-up">
                <label className="text-xs font-bold text-text-primary uppercase tracking-wider flex items-center gap-1.5">
                  <Clock className="w-4 h-4 text-text-muted" /> Select Available Appointment Slot
                </label>

                {loadingSlots ? (
                  <div className="h-10 border border-border rounded-xl flex items-center px-3 bg-surface-secondary text-xs text-text-muted gap-2">
                    <Loader2 className="w-4 h-4 animate-spin text-primary-600" /> Retrieving available times...
                  </div>
                ) : slots.length === 0 ? (
                  <div className="p-3 bg-amber-50 border border-amber-200 text-amber-800 text-xs rounded-xl font-medium">
                    No open availability slots for this doctor. Please select another doctor.
                  </div>
                ) : (
                  <div className="grid grid-cols-2 sm:grid-cols-3 gap-2.5">
                    {slots.map((slot) => {
                      const isSelected = selectedSlot === slot.id;
                      const dateFormatted = new Date(slot.date).toLocaleDateString("en-IN", {
                        month: "short",
                        day: "numeric",
                      });
                      
                      return (
                        <button
                          key={slot.id}
                          type="button"
                          onClick={() => setSelectedSlot(slot.id)}
                          className={`text-left p-3 border rounded-xl transition-all cursor-pointer ${
                            isSelected
                              ? "bg-primary-50 border-primary-500 text-primary-700 font-semibold ring-1 ring-primary-500"
                              : "border-border hover:bg-surface-secondary text-text-primary"
                          }`}
                        >
                          <span className="text-xs text-text-muted block font-medium">{dateFormatted}</span>
                          <span className="text-sm font-bold block mt-0.5">{slot.startTime}</span>
                        </button>
                      );
                    })}
                  </div>
                )}
              </div>
            )}

            {/* Step 4: Appointment Mode / Type */}
            {selectedSlot && (
              <div className="space-y-4 animate-slide-up border-t border-border pt-6">
                <h3 className="text-xs font-bold text-text-primary uppercase tracking-wider">Consultation Parameters</h3>

                {/* Consultation Type Selector */}
                <div className="grid grid-cols-2 gap-4">
                  <button
                    type="button"
                    onClick={() => setAppointmentType("IN_PERSON")}
                    className={`p-4 border rounded-2xl flex flex-col items-center justify-center text-center cursor-pointer transition-all ${
                      appointmentType === "IN_PERSON"
                        ? "bg-primary-50 border-primary-500 text-primary-700 font-semibold ring-1 ring-primary-500"
                        : "border-border hover:bg-surface-secondary text-text-primary"
                    }`}
                  >
                    <Building2 className="w-6 h-6 mb-2" />
                    <span className="text-sm block">In-Person Visit</span>
                    <span className="text-[10px] text-text-muted block mt-0.5">Consult at clinic room</span>
                  </button>

                  <button
                    type="button"
                    onClick={() => setAppointmentType("VIDEO_CALL")}
                    className={`p-4 border rounded-2xl flex flex-col items-center justify-center text-center cursor-pointer transition-all ${
                      appointmentType === "VIDEO_CALL"
                        ? "bg-primary-50 border-primary-500 text-primary-700 font-semibold ring-1 ring-primary-500"
                        : "border-border hover:bg-surface-secondary text-text-primary"
                    }`}
                  >
                    <Video className="w-6 h-6 mb-2" />
                    <span className="text-sm block">Video Consultation</span>
                    <span className="text-[10px] text-text-muted block mt-0.5">Connect online via secure room</span>
                  </button>
                </div>

                {/* Reason input */}
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-text-primary uppercase tracking-wider flex items-center gap-1.5">
                    <FileText className="w-4 h-4 text-text-muted" /> Brief Symptoms / Reason for Visit
                  </label>
                  <textarea
                    rows={2}
                    placeholder="e.g. Regular cardiac checkup, chest discomfort..."
                    value={reason}
                    onChange={(e) => setReason(e.target.value)}
                    className="w-full text-sm border border-border rounded-xl px-3.5 py-2.5 bg-white text-text-primary focus:outline-none focus:border-primary-500"
                  />
                </div>

                {/* Financial Summary */}
                {selectedDoctorObj && (
                  <div className="bg-surface-secondary/50 border border-border rounded-2xl p-4 flex justify-between items-center text-sm">
                    <span className="text-text-secondary flex items-center gap-1.5">
                      <CreditCard className="w-4 h-4 text-text-muted" /> Consultation Charges
                    </span>
                    <span className="font-extrabold text-text-primary text-base">
                      ₹{selectedDoctorObj.consultationFee}
                    </span>
                  </div>
                )}
              </div>
            )}

            {/* Submit button */}
            {selectedSlot && (
              <button
                type="submit"
                disabled={saving}
                className="w-full py-3.5 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-2xl transition-all shadow-xs flex items-center justify-center gap-2 cursor-pointer disabled:opacity-50 text-sm mt-8"
              >
                {saving ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" /> Finalizing Booking Request...
                  </>
                ) : (
                  "Confirm Booking"
                )}
              </button>
            )}
          </form>
        </div>
      </main>
    </div>
  );
}

export default function NewAppointmentPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <Loader2 className="w-8 h-8 text-primary-600 animate-spin" />
      </div>
    }>
      <NewAppointmentForm />
    </Suspense>
  );
}
